import React from 'react';
import { useParams } from 'react-router-dom';
import useFetchProducts from '../hooks/useFetchProducts';
import ProductCard from '../components/ProductCard';

const ProductPage = () => {
  const { productId } = useParams<{ productId: string }>();
  const { products, loading, error } = useFetchProducts();
  const product = products.find(p => p.id === productId);

  if (loading) return <p>Loading product details...</p>;
  if (error || !product) return <p>Product not found.</p>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row gap-6">
        <img src={product.image} alt={product.name} className="w-full md:w-1/2 rounded-xl" />
        <div className="flex-1">
          <h2 className="text-2xl font-bold mb-2">{product.name}</h2>
          <p className="text-gray-400 mb-4">{product.description}</p>
          <p className="text-lg font-semibold mb-4">${product.price}</p>
          <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to Cart</button>
        </div>
      </div>
      <div className="mt-8">
        <h3 className="text-xl font-semibold mb-4">Related Products</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {products.filter(p => p.id !== productId).slice(0, 3).map(relatedProduct => (
            <ProductCard key={relatedProduct.id} product={relatedProduct} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default ProductPage;

